import{_ as A,c as e,o as a,a as t}from"./app.0a988d3b.js";const n='{"title":"Transform","description":"","frontmatter":{},"headers":[{"level":2,"title":"Scale","slug":"scale"},{"level":2,"title":"Skew","slug":"skew"},{"level":3,"title":"Rotate","slug":"rotate"},{"level":3,"title":"Translate","slug":"translate"}],"relativePath":"docs/css/Transform.md"}',s={},o=[t('<h1 id="transform" tabindex="-1">Transform <a class="header-anchor" href="#transform" aria-hidden="true">#</a></h1><h2 id="scale" tabindex="-1">Scale <a class="header-anchor" href="#scale" aria-hidden="true">#</a></h2><p>缩放一个元素</p><ul><li><code>transform: scale(2, .5)</code></li><li><code>transform: scaleX(2)</code></li><li><code>transform: scaleY(.5)</code></li></ul><h2 id="skew" tabindex="-1">Skew <a class="header-anchor" href="#skew" aria-hidden="true">#</a></h2><p>让元素发生偏斜</p><ul><li><code> transform: skewX(25deg)</code></li><li><code>transform: skewY(25deg)</code></li><li><code>transform: skew(25deg, 25deg)</code></li></ul><blockquote><p>Before</p></blockquote><p><img src="data:image/png;base64," alt=""></p><blockquote><p>After(<code>skewX(25deg)</code>)</p></blockquote><p><img src="/assets/image-20220529161701771.7633b31e.png" alt=""></p><h3 id="rotate" tabindex="-1">Rotate <a class="header-anchor" href="#rotate" aria-hidden="true">#</a></h3><p>让元素发生旋转（默认为顺时针）</p><ul><li><code>transform: rotate(25deg)</code></li></ul><h3 id="translate" tabindex="-1">Translate <a class="header-anchor" href="#translate" aria-hidden="true">#</a></h3><p>This transform function moves an element sideways, or up and down.</p><blockquote><p>小范围内改动</p></blockquote><ul><li><code>transform: translate(20px, 10px)</code></li><li><code>translateX(value)</code></li><li><code>translateY(value)</code></li></ul><p>注意方向：</p><ul><li>X轴：左正右负</li><li>Y轴：下正上负（和数学中的不一样）</li></ul><p>It’s important to note that an element using <code>transform</code> <strong>will not cause</strong> other elements to <strong>flow</strong> around it.</p><blockquote><p>其他元素不会动，就是会发生重叠，可以考虑用<code>z-index</code>来达到期望中的效果</p></blockquote><p>It’s also worth noting that <code>translate</code> will be hardware accelerated if you want to animate that property, <strong>unlike</strong> <code>position: absolute</code>.</p>',23)];var r=A(s,[["render",function(A,t,n,s,r,l){return a(),e("div",null,o)}]]);export{n as __pageData,r as default};
